"use client"

import React, { useEffect, useState, useRef, useCallback } from 'react'
import Link from 'next/link'
import { supabase } from '@/lib/supabase'

type Post = {
  id: string
  content: string
  likes_count: number
  comments_count: number
  created_at: string
  user_full_name?: string
  user_username?: string
  user_profile_image?: string
  user_id?: string
  user_liked?: boolean
}

type Comment = {
  id: string
  content: string
  created_at: string
  author_username?: string
  user_profile_image?: string
}

export default function CommunityFeed() {
  const [posts, setPosts] = useState<Post[]>([])
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState<string | null>(null)
  const [pendingLikes, setPendingLikes] = useState<Record<string, boolean>>({})
  const [commentsOpen, setCommentsOpen] = useState<Record<string, boolean>>({})
  const [commentsByPost, setCommentsByPost] = useState<Record<string, Comment[]>>({})
  const [commentsLoading, setCommentsLoading] = useState<Record<string, boolean>>({})
  const [commentInputs, setCommentInputs] = useState<Record<string, string>>({})
  const [submittingComment, setSubmittingComment] = useState<Record<string, boolean>>({})
  const realtimeSubs = useRef<Map<string, any>>(new Map())
  const mountedRef = useRef(true)

  // New post creation state
  const [newPostContent, setNewPostContent] = useState('')
  const [isCreatingPost, setIsCreatingPost] = useState(false)
  const [createPostError, setCreatePostError] = useState<string | null>(null)
  const [currentUserId, setCurrentUserId] = useState<string | null>(null)
  const [currentUser, setCurrentUser] = useState<{ id: string; full_name?: string; profile_image_url?: string } | null>(null)

  // Feed filter state: 'all' or 'following'
  const [feedFilter, setFeedFilter] = useState<'all' | 'following'>('following')

  // Cleanup subscriptions on unmount
  useEffect(() => {
    mountedRef.current = true
    return () => {
      mountedRef.current = false
      // Cleanup all realtime subscriptions
      realtimeSubs.current.forEach((channel) => {
        try {
          channel.unsubscribe()
        } catch (e) {
          // ignore cleanup errors
        }
      })
      realtimeSubs.current.clear()
    }
  }, [])

  // Helper to make authenticated API requests
  const makeAuthenticatedRequest = useCallback(async (body: any) => {
    const { data: sessionData } = await supabase.auth.getSession()
    const token = sessionData?.session?.access_token

    const headers: Record<string, string> = { 'Content-Type': 'application/json' }
    if (token) headers['Authorization'] = `Bearer ${token}`

    const res = await fetch('/api/supabase/functions/community-handler', {
      method: 'POST',
      headers,
      body: JSON.stringify(body)
    })

    const data = await res.json().catch(() => ({}))
    return { ok: res.ok, data }
  }, [])

  // Get current user on mount
  useEffect(() => {
    async function fetchCurrentUser() {
      const { data: { user } } = await supabase.auth.getUser()
      if (user) {
        setCurrentUserId(user.id)
        // Also fetch user profile for avatar display
        const { data: profile } = await supabase
          .from('users')
          .select('id, full_name, username, profile_image_url')
          .eq('id', user.id)
          .single()
        if (profile) {
          setCurrentUser(profile)
        }
      }
    }
    fetchCurrentUser()
  }, [])

  // Map RPC row to Post type
  const mapRpcPostToPost = useCallback((fp: any): Post => ({
    id: fp.id,
    content: fp.content,
    likes_count: Number(fp.likes_count || 0),
    comments_count: fp.comments_count || 0,
    created_at: fp.created_at,
    user_full_name: fp.author_username || fp.user_full_name || '',
    user_username: fp.author_username || fp.user_username || '',
    user_profile_image: fp.author_profile_image || fp.user_profile_image || '',
    user_id: fp.author_id || fp.user_id || '',
    user_liked: !!fp.user_has_liked
  }), [])

  // Load posts based on current filter
  const loadPosts = useCallback(async () => {
    if (!mountedRef.current) return
    setLoading(true)
    setError(null)

    try {
      if (feedFilter === 'following') {
        // Load only posts from users we follow
        console.log('[CommunityFeed] Loading following posts')
        const { ok, data } = await makeAuthenticatedRequest({ action: 'get-following-posts' })
        
        if (!ok || !data.success) {
          if (mountedRef.current) {
            // If not authenticated, show message
            if (data?.error === 'Authentication required') {
              setError('Please sign in to see posts from people you follow.')
            } else {
              setError(data?.error || 'Failed to load posts')
            }
            setPosts([])
          }
        } else {
          if (mountedRef.current) {
            setPosts(data.posts || [])
          }
        }
      } else {
        // Load all posts (explore mode)
        console.log('[CommunityFeed] Loading all posts')
        // Try RPC first for better data accuracy
        const { data: rpcPosts, error: rpcError } = await supabase.rpc('get_posts_with_like_details')

        if (!rpcError && Array.isArray(rpcPosts) && rpcPosts.length >= 0) {
          if (mountedRef.current) {
            setPosts(rpcPosts.map(mapRpcPostToPost))
          }
        } else {
          // Fallback to API handler
          console.log('[CommunityFeed] RPC failed, falling back to API:', rpcError?.message)
          const { ok, data } = await makeAuthenticatedRequest({ action: 'get-community-posts' })
          
          if (!ok || !data.success) {
            if (mountedRef.current) {
              setError(data?.error || 'Failed to load posts')
              setPosts([])
            }
          } else {
            if (mountedRef.current) {
              setPosts(data.posts || [])
            }
          }
        }
      }
    } catch (e) {
      console.error('[CommunityFeed] Failed to fetch posts:', e)
      if (mountedRef.current) {
        setError('Failed to load posts. Please try again.')
        setPosts([])
      }
    } finally {
      if (mountedRef.current) {
        setLoading(false)
      }
    }
  }, [makeAuthenticatedRequest, mapRpcPostToPost, feedFilter])

  useEffect(() => {
    loadPosts()
  }, [loadPosts])

  // Create a new post
  const createPost = async () => {
    const content = newPostContent.trim()
    if (!content) return

    if (!currentUserId) {
      setCreatePostError('Please sign in to create a post.')
      return
    }

    if (content.length > 500) {
      setCreatePostError('Post content is too long (max 500 characters).')
      return
    }

    setIsCreatingPost(true)
    setCreatePostError(null)

    try {
      const { ok, data } = await makeAuthenticatedRequest({
        action: 'create-post',
        content
      })

      if (ok && data.success && data.post) {
        // Add the new post to the top of the list optimistically
        const newPost: Post = {
          id: data.post.id,
          content: data.post.content,
          likes_count: 0,
          comments_count: 0,
          created_at: data.post.created_at,
          user_full_name: currentUser?.full_name || '',
          user_username: currentUser?.full_name || '',
          user_profile_image: currentUser?.profile_image_url || '',
          user_id: currentUserId,
          user_liked: false
        }
        setPosts(prev => [newPost, ...prev])
        setNewPostContent('')
      } else {
        setCreatePostError(data?.error || 'Failed to create post. Please try again.')
      }
    } catch (e) {
      console.error('[CommunityFeed] Create post error:', e)
      setCreatePostError('Failed to create post. Please try again.')
    } finally {
      setIsCreatingPost(false)
    }
  }

  // Toggle like on a post
  async function toggleLike(postId: string) {
    if (!currentUserId) {
      setError('Please sign in to like posts.')
      return
    }

    // Optimistic update
    setPendingLikes(prev => ({ ...prev, [postId]: true }))
    const originalPosts = [...posts]
    
    setPosts(prev => prev.map(p => {
      if (p.id !== postId) return p
      return {
        ...p,
        user_liked: !p.user_liked,
        likes_count: p.user_liked ? Math.max(0, (p.likes_count || 0) - 1) : (p.likes_count || 0) + 1
      }
    }))

    try {
      // Try RPC first
      const { data: rpcData, error: rpcError } = await supabase.rpc('toggle_like', { post_id_to_toggle: postId })

      if (rpcError) {
        console.error('[toggleLike] RPC error:', rpcError)
        // Try API fallback
        const { ok, data } = await makeAuthenticatedRequest({ action: 'like-post', postId })
        
        if (!ok || !data.success) {
          // Revert optimistic update
          setPosts(originalPosts)
          return
        }

        // Update with server response
        if (typeof data.likes_count === 'number') {
          setPosts(prev => prev.map(p => p.id === postId ? { ...p, likes_count: data.likes_count, user_liked: data.liked } : p))
        }
      } else {
        // RPC succeeded, refresh posts to get accurate counts
        const { data: freshPosts, error: freshError } = await supabase.rpc('get_posts_with_like_details')
        if (!freshError && Array.isArray(freshPosts)) {
          setPosts(freshPosts.map(mapRpcPostToPost))
        }
      }
    } catch (e) {
      console.error('[toggleLike] Error:', e)
      // Revert optimistic update
      setPosts(originalPosts)
    } finally {
      setPendingLikes(prev => {
        const copy = { ...prev }
        delete copy[postId]
        return copy
      })
    }
  }

  // Fetch comments for a post
  async function fetchComments(postId: string) {
    setCommentsLoading(prev => ({ ...prev, [postId]: true }))
    try {
      // Try RPC first
      const { data, error } = await supabase.rpc('get_comments_for_post', { post_id_to_fetch: postId })
      
      if (error) {
        console.log('[fetchComments] RPC error, trying API:', error.message)
        // Fallback to API
        const { ok, data: apiData } = await makeAuthenticatedRequest({ action: 'get-post-comments', postId })
        if (ok && apiData?.success) {
          const mapped = (apiData.comments || []).map((c: any) => ({
            id: c.id,
            content: c.content,
            created_at: c.created_at,
            author_username: c.user_full_name || c.user_username || 'User',
            user_profile_image: c.user_profile_image
          }))
          setCommentsByPost(prev => ({ ...prev, [postId]: mapped }))
          setPosts(prev => prev.map(p => p.id === postId ? { ...p, comments_count: mapped.length } : p))
        } else {
          setCommentsByPost(prev => ({ ...prev, [postId]: [] }))
        }
      } else if (Array.isArray(data)) {
        const mapped = data.map((c: any) => ({
          id: c.id,
          content: c.content,
          created_at: c.created_at,
          author_username: c.author_username || 'User',
          user_profile_image: c.author_profile_image
        }))
        setCommentsByPost(prev => ({ ...prev, [postId]: mapped }))
        setPosts(prev => prev.map(p => p.id === postId ? { ...p, comments_count: mapped.length } : p))
      } else {
        setCommentsByPost(prev => ({ ...prev, [postId]: [] }))
      }
    } catch (e) {
      console.error('[fetchComments] Error:', e)
      setCommentsByPost(prev => ({ ...prev, [postId]: [] }))
    } finally {
      setCommentsLoading(prev => ({ ...prev, [postId]: false }))
    }
  }

  // Subscribe to realtime comment updates
  function subscribeToComments(postId: string) {
    if (realtimeSubs.current.has(postId)) return

    const channel = supabase
      .channel(`post_comments:${postId}`)
      .on(
        'postgres_changes',
        { event: 'INSERT', schema: 'public', table: 'post_comments', filter: `post_id=eq.${postId}` },
        (payload) => {
          try {
            const newRow = (payload as any).new
            if (!newRow || !newRow.is_active) return
            
            // Avoid duplicate if we already have this comment
            setCommentsByPost(prev => {
              const list = prev[postId] || []
              if (list.some(c => c.id === newRow.id)) return prev
              
              const comment: Comment = {
                id: newRow.id,
                content: newRow.content,
                created_at: newRow.created_at,
                author_username: newRow.author_username || 'User'
              }
              const next = [...list, comment].sort((a, b) => 
                new Date(a.created_at).getTime() - new Date(b.created_at).getTime()
              )
              return { ...prev, [postId]: next }
            })
            
            // Update comment count
            setPosts(prev => prev.map(p => 
              p.id === postId ? { ...p, comments_count: (p.comments_count || 0) + 1 } : p
            ))
          } catch (e) {
            console.error('[subscribeToComments] Handler error:', e)
          }
        }
      )
      .subscribe()

    realtimeSubs.current.set(postId, channel)
  }

  async function unsubscribeFromComments(postId: string) {
    const channel = realtimeSubs.current.get(postId)
    if (!channel) return
    try {
      await channel.unsubscribe()
    } catch (e) {
      console.warn('[unsubscribeFromComments] Error:', e)
    }
    realtimeSubs.current.delete(postId)
  }

  // Toggle comments panel
  async function toggleComments(postId: string) {
    const isOpen = !!commentsOpen[postId]
    if (isOpen) {
      setCommentsOpen(prev => ({ ...prev, [postId]: false }))
      await unsubscribeFromComments(postId)
    } else {
      setCommentsOpen(prev => ({ ...prev, [postId]: true }))
      await fetchComments(postId)
      subscribeToComments(postId)
    }
  }

  // Submit a comment
  async function submitComment(postId: string) {
    const content = (commentInputs[postId] || '').trim()
    if (!content) return
    if (!currentUserId) {
      setError('Please sign in to comment.')
      return
    }

    setSubmittingComment(prev => ({ ...prev, [postId]: true }))

    try {
      const { ok, data } = await makeAuthenticatedRequest({
        action: 'create-comment',
        postId,
        content
      })

      if (ok && data.success) {
        // Clear input
        setCommentInputs(prev => ({ ...prev, [postId]: '' }))
        
        // Add comment optimistically (realtime will also deliver it, but we check for duplicates)
        if (data.comment) {
          const newComment: Comment = {
            id: data.comment.id,
            content: data.comment.content,
            created_at: data.comment.created_at,
            author_username: currentUser?.full_name || 'You',
            user_profile_image: currentUser?.profile_image_url
          }
          
          setCommentsByPost(prev => {
            const list = prev[postId] || []
            if (list.some(c => c.id === newComment.id)) return prev
            return { ...prev, [postId]: [...list, newComment] }
          })
        }
        
        // Update comment count
        if (typeof data.comments_count === 'number') {
          setPosts(prev => prev.map(p => p.id === postId ? { ...p, comments_count: data.comments_count } : p))
        } else {
          setPosts(prev => prev.map(p => p.id === postId ? { ...p, comments_count: (p.comments_count || 0) + 1 } : p))
        }
      } else {
        console.error('[submitComment] Failed:', data?.error)
      }
    } catch (e) {
      console.error('[submitComment] Error:', e)
    } finally {
      setSubmittingComment(prev => ({ ...prev, [postId]: false }))
    }
  }

  // Delete a post (only for the owner)
  async function deletePost(postId: string) {
    if (!confirm('Are you sure you want to delete this post?')) return

    const originalPosts = [...posts]
    // Optimistic removal
    setPosts(prev => prev.filter(p => p.id !== postId))

    try {
      const { ok, data } = await makeAuthenticatedRequest({
        action: 'delete-post',
        postId
      })

      if (!ok || !data.success) {
        // Revert
        setPosts(originalPosts)
        alert(data?.error || 'Failed to delete post')
      }
    } catch (e) {
      console.error('[deletePost] Error:', e)
      setPosts(originalPosts)
      alert('Failed to delete post. Please try again.')
    }
  }

  if (loading) {
    return (
      <div className="py-8 flex items-center justify-center">
        <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-green-600"></div>
        <span className="ml-3 text-gray-600">Loading posts...</span>
      </div>
    )
  }

  if (error && posts.length === 0) {
    return (
      <div className="py-8">
        <div className="text-red-600 mb-4">{error}</div>
        <button 
          onClick={loadPosts}
          className="px-4 py-2 bg-green-600 text-white rounded-lg hover:bg-green-700"
        >
          Try Again
        </button>
      </div>
    )
  }

  return (
    <div className="space-y-6">
      {/* Create Post Form */}
      {currentUserId && (
        <div className="bg-white shadow rounded-lg p-4">
          <div className="flex gap-3">
            <div className="h-10 w-10 rounded-full bg-gray-100 overflow-hidden flex items-center justify-center flex-shrink-0">
              {currentUser?.profile_image_url ? (
                <img src={currentUser.profile_image_url} alt="Your avatar" className="h-full w-full object-cover" />
              ) : (
                <span className="text-sm text-gray-600">
                  {(currentUser?.full_name || 'U').slice(0, 1).toUpperCase()}
                </span>
              )}
            </div>
            <div className="flex-1">
              <textarea
                value={newPostContent}
                onChange={(e) => setNewPostContent(e.target.value)}
                placeholder="Share something with the community..."
                className="w-full border border-gray-200 rounded-lg p-3 text-sm resize-none focus:outline-none focus:ring-2 focus:ring-green-500 focus:border-transparent"
                rows={3}
                maxLength={500}
              />
              <div className="flex items-center justify-between mt-2">
                <span className="text-xs text-gray-500">
                  {newPostContent.length}/500 characters
                </span>
                <button
                  onClick={createPost}
                  disabled={isCreatingPost || !newPostContent.trim()}
                  className={`px-4 py-2 rounded-lg text-sm font-medium transition-colors ${
                    isCreatingPost || !newPostContent.trim()
                      ? 'bg-gray-200 text-gray-400 cursor-not-allowed'
                      : 'bg-green-600 text-white hover:bg-green-700'
                  }`}
                >
                  {isCreatingPost ? 'Posting...' : 'Post'}
                </button>
              </div>
              {createPostError && (
                <div className="mt-2 text-sm text-red-600">{createPostError}</div>
              )}
            </div>
          </div>
        </div>
      )}

      {/* Sign in prompt for non-authenticated users */}
      {!currentUserId && !loading && (
        <div className="bg-white shadow rounded-lg p-4 text-center">
          <p className="text-gray-600 mb-3">Sign in to share posts and interact with the community!</p>
          <Link href="/login" className="inline-block px-4 py-2 bg-green-600 text-white rounded-lg hover:bg-green-700">
            Sign In
          </Link>
        </div>
      )}

      {/* Error notification */}
      {error && posts.length > 0 && (
        <div className="bg-yellow-50 border border-yellow-200 text-yellow-800 px-4 py-3 rounded-lg">
          {error}
          <button onClick={() => setError(null)} className="ml-2 text-yellow-600 hover:text-yellow-700">
            Dismiss
          </button>
        </div>
      )}

      {/* Feed Filter Tabs */}
      <div className="bg-white shadow rounded-lg p-1 flex gap-1">
        <button
          onClick={() => setFeedFilter('following')}
          className={`flex-1 py-2.5 px-4 rounded-md text-sm font-medium transition-all ${
            feedFilter === 'following'
              ? 'bg-green-600 text-white shadow-sm'
              : 'text-gray-600 hover:bg-gray-100'
          }`}
        >
          Following
        </button>
        <button
          onClick={() => setFeedFilter('all')}
          className={`flex-1 py-2.5 px-4 rounded-md text-sm font-medium transition-all ${
            feedFilter === 'all'
              ? 'bg-green-600 text-white shadow-sm'
              : 'text-gray-600 hover:bg-gray-100'
          }`}
        >
          Explore
        </button>
      </div>

      {/* Posts List */}
      {posts.length === 0 && !loading && (
        <div className="text-gray-500 py-6 text-center bg-white shadow rounded-lg">
          {feedFilter === 'following' ? (
            <div className="space-y-2">
              <p>No posts from people you follow yet.</p>
              <p className="text-sm">
                Switch to <button onClick={() => setFeedFilter('all')} className="text-green-600 hover:underline font-medium">Explore</button> to discover new people to follow!
              </p>
            </div>
          ) : (
            'No posts yet — be the first to share!'
          )}
        </div>
      )}

      {posts.map(post => (
        <article key={post.id} className="bg-white shadow rounded-lg p-4">
          <div className="flex items-start gap-3">
            <Link 
              href={post.user_id ? `/community/profile/${post.user_id}` : '/profile'} 
              className="h-10 w-10 rounded-full bg-gray-100 overflow-hidden flex items-center justify-center flex-shrink-0"
            >
              {post.user_profile_image ? (
                <img src={post.user_profile_image} alt="avatar" className="h-full w-full object-cover" />
              ) : (
                <span className="text-sm text-gray-600">
                  {(post.user_full_name || post.user_username || 'U').slice(0, 1).toUpperCase()}
                </span>
              )}
            </Link>
            <div className="flex-1 min-w-0">
              <div className="flex items-center justify-between">
                <div>
                  <Link 
                    href={post.user_id ? `/community/profile/${post.user_id}` : '/profile'} 
                    className="text-sm font-medium text-gray-800 hover:underline"
                  >
                    {post.user_full_name || post.user_username || 'Unknown'}
                  </Link>
                  <div className="text-xs text-gray-500">
                    {new Date(post.created_at).toLocaleString()}
                  </div>
                </div>
                {/* Delete button for post owner */}
                {currentUserId === post.user_id && (
                  <button
                    onClick={() => deletePost(post.id)}
                    className="text-gray-400 hover:text-red-600 p-1"
                    title="Delete post"
                  >
                    <i className="ri-delete-bin-line" />
                  </button>
                )}
              </div>

              <div className="mt-3 text-gray-800 whitespace-pre-wrap break-words">
                {post.content}
              </div>

              {/* Actions */}
              <div className="mt-4 flex items-center gap-4">
                <button
                  type="button"
                  aria-pressed={post.user_liked}
                  onClick={() => toggleLike(post.id)}
                  disabled={!!pendingLikes[post.id]}
                  className={`flex items-center gap-2 px-3 py-2 rounded-lg transition-colors ${
                    pendingLikes[post.id] ? 'opacity-60 cursor-not-allowed' : 'cursor-pointer'
                  } ${
                    post.user_liked ? 'text-red-600 bg-red-50' : 'text-gray-600 hover:bg-gray-50'
                  }`}
                >
                  <i className={post.user_liked ? 'ri-heart-fill' : 'ri-heart-line'} />
                  <span className="text-sm">{post.likes_count ?? 0}</span>
                </button>

                <button
                  type="button"
                  onClick={() => toggleComments(post.id)}
                  className="flex items-center gap-2 text-gray-600 px-3 py-2 rounded-lg hover:bg-gray-50 transition-colors"
                >
                  <i className="ri-chat-3-line" />
                  <span className="text-sm">{post.comments_count ?? 0}</span>
                </button>
              </div>
            </div>
          </div>

          {/* Comments Panel */}
          {commentsOpen[post.id] && (
            <div className="mt-4 border-t pt-4">
              {commentsLoading[post.id] ? (
                <div className="flex items-center text-sm text-gray-500">
                  <div className="animate-spin rounded-full h-4 w-4 border-b-2 border-gray-400 mr-2"></div>
                  Loading comments...
                </div>
              ) : (
                <div className="space-y-3">
                  {(commentsByPost[post.id] || []).length === 0 && (
                    <div className="text-sm text-gray-500">No comments yet. Be the first to comment!</div>
                  )}
                  
                  {(commentsByPost[post.id] || []).map(comment => (
                    <div key={comment.id} className="flex items-start gap-2 py-2">
                      <div className="h-8 w-8 rounded-full bg-gray-100 flex items-center justify-center flex-shrink-0 text-xs">
                        {comment.user_profile_image ? (
                          <img src={comment.user_profile_image} alt="" className="h-full w-full rounded-full object-cover" />
                        ) : (
                          (comment.author_username || 'U').slice(0, 1).toUpperCase()
                        )}
                      </div>
                      <div className="flex-1 min-w-0">
                        <div className="text-sm font-medium text-gray-800">
                          {comment.author_username || 'User'}
                        </div>
                        <div className="text-sm text-gray-700 whitespace-pre-wrap break-words">
                          {comment.content}
                        </div>
                        <div className="text-xs text-gray-400 mt-1">
                          {new Date(comment.created_at).toLocaleString()}
                        </div>
                      </div>
                    </div>
                  ))}

                  {/* Comment Input */}
                  {currentUserId ? (
                    <div className="pt-3 border-t">
                      <textarea
                        value={commentInputs[post.id] || ''}
                        onChange={(e) => setCommentInputs(prev => ({ ...prev, [post.id]: e.target.value }))}
                        placeholder="Write a comment..."
                        className="w-full border border-gray-200 rounded-lg p-2 text-sm resize-none focus:outline-none focus:ring-2 focus:ring-green-500"
                        rows={2}
                        maxLength={500}
                      />
                      <div className="mt-2 flex justify-end">
                        <button
                          onClick={() => submitComment(post.id)}
                          disabled={submittingComment[post.id] || !(commentInputs[post.id] || '').trim()}
                          className={`px-3 py-1.5 rounded-lg text-sm font-medium transition-colors ${
                            submittingComment[post.id] || !(commentInputs[post.id] || '').trim()
                              ? 'bg-gray-200 text-gray-400 cursor-not-allowed'
                              : 'bg-green-600 text-white hover:bg-green-700'
                          }`}
                        >
                          {submittingComment[post.id] ? 'Posting...' : 'Comment'}
                        </button>
                      </div>
                    </div>
                  ) : (
                    <div className="pt-3 border-t text-center">
                      <Link href="/login" className="text-sm text-green-600 hover:text-green-700">
                        Sign in to comment
                      </Link>
                    </div>
                  )}
                </div>
              )}
            </div>
          )}
        </article>
      ))}
    </div>
  )
}
