"use client"

import React, { useEffect, useState } from 'react'
import Link from 'next/link'
import Chatbot from '@/components/Chatbot'
import CommunityFeed from '@/components/CommunityFeed'
import { supabase } from '@/lib/supabase'

type User = {
  id: string
  full_name?: string
  username?: string
  profile_image_url?: string
  eco_points?: number
}

export default function CommunityPage() {
  const [activeTab, setActiveTab] = useState<'feed' | 'users' | 'impact'>('feed')

  // Users state
  const [users, setUsers] = useState<User[]>([])
  const [loadingUsers, setLoadingUsers] = useState(false)
  const [searchQuery, setSearchQuery] = useState('')
  const [searchResults, setSearchResults] = useState<User[] | null>(null)
  const [loadingSearch, setLoadingSearch] = useState(false)

  // Impact state
  const [impact, setImpact] = useState({ active_members: 0, posts_today: 0 })
  const [loadingImpact, setLoadingImpact] = useState(false)

  async function makeAuthenticatedRequest(body: any) {
    const { data: sessionData } = await supabase.auth.getSession()
    const token = (sessionData as any)?.session?.access_token || null

    const res = await fetch('/api/supabase/functions/community-handler', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        ...(token ? { Authorization: `Bearer ${token}` } : {})
      },
      body: JSON.stringify(body)
    })

    const data = await res.json().catch(() => ({}))
    return { ok: res.ok, data }
  }

  useEffect(() => {
    // Load users when switching to users tab
    if (activeTab === 'users' && users.length === 0) {
      ;(async () => {
        setLoadingUsers(true)
        try {
          const { ok, data } = await makeAuthenticatedRequest({ action: 'get-community-users' })
          if (ok && data?.success) {
            setUsers(data.users || [])
          }
        } catch (e) {
          console.error('Error loading users', e)
        } finally {
          setLoadingUsers(false)
        }
      })()
    }

    // Load impact when switching to impact tab
    if (activeTab === 'impact') {
      ;(async () => {
        setLoadingImpact(true)
        try {
          const { ok, data } = await makeAuthenticatedRequest({ action: 'get-community-impact' })
          if (ok && data?.success) {
            setImpact(data.impact || impact)
          }
        } catch (e) {
          console.error('Error loading impact', e)
        } finally {
          setLoadingImpact(false)
        }
      })()
    }
  }, [activeTab])

  // Search users when query changes (debounced)
  useEffect(() => {
    let mounted = true
    const q = searchQuery.trim()
    const timer = setTimeout(async () => {
      if (q.length < 2) {
        if (mounted) setSearchResults(null)
        return
      }

      setLoadingSearch(true)
      try {
        const { ok, data } = await makeAuthenticatedRequest({ action: 'search-users', q })
        if (ok && data?.success) {
          if (mounted) setSearchResults(data.users || [])
        } else {
          if (mounted) setSearchResults([])
        }
      } catch (e) {
        console.error('Search error', e)
        if (mounted) setSearchResults([])
      } finally {
        if (mounted) setLoadingSearch(false)
      }
    }, 350)

    return () => { mounted = false; clearTimeout(timer) }
  }, [searchQuery])

  return (
    <div className="min-h-screen bg-gradient-to-br from-green-50 to-emerald-50">
      <div className="container mx-auto px-4 py-6 max-w-7xl">
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6 items-start">

          {/* Main content */}
          <main className="col-span-1 md:col-span-2">
            <div className="bg-white shadow rounded-lg">
              <header className="px-6 py-4 border-b border-gray-100">
                <h1 className="text-2xl font-semibold">Community</h1>
                <p className="text-sm text-gray-600">Connect, share, and find other members.</p>
              </header>

              {/* Tabs / nav */}
              <nav className="px-4 border-b border-gray-200">
                <div className="flex overflow-x-auto">
                  <button
                    onClick={() => setActiveTab('feed')}
                    className={`px-6 py-4 font-medium whitespace-nowrap ${
                      activeTab === 'feed' ? 'border-b-2 border-green-500 text-green-600' : 'text-gray-600 hover:text-gray-800'
                    }`}
                  >
                    <i className="ri-home-line mr-2" />
                    Community Feed
                  </button>

                  <button
                    onClick={() => setActiveTab('users')}
                    className={`px-6 py-4 font-medium whitespace-nowrap ${
                      activeTab === 'users' ? 'border-b-2 border-green-500 text-green-600' : 'text-gray-600 hover:text-gray-800'
                    }`}
                  >
                    <i className="ri-group-line mr-2" />
                    Find Users
                  </button>

                  <button
                    onClick={() => setActiveTab('impact')}
                    className={`px-6 py-4 font-medium whitespace-nowrap ${
                      activeTab === 'impact' ? 'border-b-2 border-green-500 text-green-600' : 'text-gray-600 hover:text-gray-800'
                    }`}
                  >
                    <i className="ri-bar-chart-line mr-2" />
                    Community Impact
                  </button>
                </div>
              </nav>

              <section className="p-6">
                {activeTab === 'feed' && (
                  <div>
                    <CommunityFeed />
                  </div>
                )}

                {activeTab === 'users' && (
                  <div>
                    <div className="mb-4">
                      <label htmlFor="user-search" className="sr-only">Search users</label>
                      <div className="relative">
                        <input
                          id="user-search"
                          value={searchQuery}
                          onChange={(e) => setSearchQuery(e.target.value)}
                          placeholder="Search users by name or username (min 2 chars)"
                          className="w-full border rounded-md px-3 py-2 shadow-sm focus:ring-1 focus:ring-green-500"
                        />
                        {loadingSearch && <div className="absolute right-3 top-2 text-sm text-gray-500">Searching…</div>}
                      </div>
                      <div className="text-xs text-gray-500 mt-1">Tip: type at least 2 characters to search.</div>
                    </div>

                    {loadingUsers && searchResults === null ? (
                      <div className="text-sm text-gray-500">Loading users…</div>
                    ) : (
                      <ul className="space-y-4">
                        {(searchResults !== null ? searchResults : users).map((u) => (
                          <li key={u.id} className="p-0">
                            <Link href={`/community/profile/${u.id}`} className="flex items-center space-x-4 p-3 bg-white border rounded hover:bg-green-50 transition-colors">
                              <img src={u.profile_image_url || '/default-avatar.png'} alt={u.full_name || u.username} className="h-10 w-10 rounded-full object-cover" />
                              <div>
                                <div className="font-medium text-gray-800">{u.full_name || u.username}</div>
                                <div className="text-xs text-gray-500">@{u.username}</div>
                              </div>
                              <div className="ml-auto text-sm text-gray-600">{u.eco_points ?? 0} pts</div>
                            </Link>
                          </li>
                        ))}
                        {searchResults !== null && searchResults.length === 0 && (
                          <li className="text-gray-500 p-3">No users found for "{searchQuery}".</li>
                        )}
                      </ul>
                    )}
                  </div>
                )}

                {activeTab === 'impact' && (
                  <div>
                    {loadingImpact ? (
                      <div className="text-sm text-gray-500">Loading metrics…</div>
                    ) : (
                      <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                        <div className="p-4 bg-white rounded shadow text-center">
                          <div className="text-2xl font-semibold">{impact.active_members}</div>
                          <div className="text-sm text-gray-500">Active members</div>
                        </div>
                        <div className="p-4 bg-white rounded shadow text-center">
                          <div className="text-2xl font-semibold">{impact.posts_today}</div>
                          <div className="text-sm text-gray-500">Posts today</div>
                        </div>
                      </div>
                    )}
                  </div>
                )}
              </section>
            </div>
          </main>

          {/* Right sidebar: Chatbot and small modules */}
          <aside className="col-span-1 md:col-span-1">
            <div className="md:sticky md:top-20 space-y-4">
              <div className="bg-white rounded-2xl shadow-md p-4">
                <h4 className="font-semibold text-gray-800">Quick links</h4>
                <ul className="text-sm text-gray-600 mt-2 space-y-2">
                  <li><Link href="/learn">Learn</Link></li>
                  <li><Link href="/donate">Donate</Link></li>
                  <li><Link href="/profile">Your profile</Link></li>
                </ul>
              </div>
              <Chatbot />
            </div>
          </aside>
        </div>
      </div>
    </div>
  )
}

